#include <stdint.h>
#include <stdlib.h>
#include <string.h> // Optional, for memcpy if used, but manual byte extraction is often clearer here.

/**
 * @brief Parses a packet buffer to extract a count N and N 8-byte records.
 *
 * The packet format is: [4 bytes: Count N (Big-Endian)] [N * 8 bytes: Records]
 *
 * @param buf The constant input buffer containing the packet data.
 * @param len The total length of the input buffer.
 * @return A pointer to a dynamically allocated array of uint64_t records,
 *         or NULL if parsing fails (buffer too short, memory allocation failure).
 *         The caller is responsible for freeing the returned array using free().
 */
uint64_t* parse_packet(const uint8_t *buf, size_t len) {
    // 1. Basic sanity check: Need at least 4 bytes for the count N.
    if (len < 4) {
        return NULL;
    }

    // 2. Read the 4-byte big-endian count N.
    // N = (buf[0] << 24) | (buf[1] << 16) | (buf[2] << 8) | buf[3]
    uint32_t count_N = 0;

    // Using pointer casting for efficient reading of the big-endian integer
    // Note: We must handle potential overflow if the count exceeds 32 bits, 
    // but since size_t is 32 bits as per requirement, this is sufficient.
    count_N = (uint32_t)buf[0] << 24 | 
               (uint32_t)buf[1] << 16 | 
               (uint32_t)buf[2] << 8 | 
               (uint32_t)buf[3];

    // Sanity check: Ensure the remaining buffer is large enough for N records (N * 8 bytes).
    // Total required size = 4 (for count) + N * 8 (for records)
    size_t required_data_len = (size_t)count_N * 8;
    size_t total_required_len = 4 + required_data_len;

    if (len < total_required_len) {
        return NULL; // Buffer truncated
    }

    // 3. Allocate memory for N records (each 8 bytes, uint64_t).
    uint64_t *records = (uint64_t *)malloc(required_data_len);
    if (records == NULL) {
        return NULL; // Memory allocation failed
    }

    // 4. Copy records from buffer into allocated memory, handling Big-Endian conversion.
    for (uint32_t i = 0; i < count_N; ++i) {
        size_t offset = 4 + (size_t)i * 8;
        uint64_t record = 0;

        // Manually convert 8 bytes (Big-Endian) into a uint64_t
        // Byte 0 is the most significant byte (MSB)
        record |= (uint64_t)buf[offset + 0] << 56;
        record |= (uint64_t)buf[offset + 1] << 48;
        record |= (uint64_t)buf[offset + 2] << 40;
        record |= (uint64_t)buf[offset + 3] << 32;
        record |= (uint64_t)buf[offset + 4] << 24;
        record |= (uint64_t)buf[offset + 5] << 16;
        record |= (uint64_t)buf[offset + 6] << 8;
        record |= (uint64_t)buf[offset + 7]; // Least significant byte (LSB)

        records[i] = record;
    }

    return records;
}

