    // Record 1 (8 bytes): 01 02 03 04 05 06 07 08
    // Record 2 (8 bytes): FF FF FF FF FF FF FF FF

    uint8_t test_buffer[] = {
        0x00, 0x00, 0x00, 0x02, // Count N = 2
        0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, // Record 1
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF  // Record 2
    };
    size_t buffer_len = sizeof(test_buffer);

    printf("Parsing packet of length: %zu\n", buffer_len);

    uint64_t *result = parse_packet(test_buffer, buffer_len);

    if (result != NULL) {
        printf("Successfully parsed packet.\n");
        printf("Count N: %lu\n", (unsigned long)2);

        for (size_t i = 0; i < 2; ++i) {
            printf("Record %zu: 0x%llX\n", i, (unsigned long long)result[i]);
        }

        free(result); // IMPORTANT: Caller must free the memory
    } else {
        printf("Parsing failed.\n");
    }

