///
/// This function performs a zero-copy conversion. It assumes the input data
/// is correctly aligned (which is often true for raw byte buffers) and that
/// the length is an exact multiple of 4 bytes.
///
/// # Arguments
///
/// * `data`: A byte slice (&[u8]) to be interpreted as u32s.
///
/// # Returns
///
/// An `Option<&[u32]>` containing the slice of u32s if the length is a
/// multiple of 4, otherwise `None`.
///
/// # Safety
///
/// This function uses `unsafe` code. The caller MUST ensure:
/// 1. `data.len()` is a multiple of `std::mem::size_of::<u32>()` (i.e., a multiple of 4).
/// 2. The memory pointed to by `data` is valid for the duration of the returned slice.
pub fn bytes_to_u32s(data: &[u8]) -> Option<&[u32]> {
    let u32_size = std::mem::size_of::<u32>();

    // 1. Check length requirement: Must be a multiple of 4 bytes.
    if data.len() % u32_size != 0 {
        return None;
    }

    let num_u32s = data.len() / u32_size;

    // 2. Safety Check: The pointer arithmetic is only safe if we trust the alignment
    // and the length check above. We cast the byte slice pointer to a u32 slice pointer.
    let u32_slice_ptr = data.as_ptr() as *const u32;

