    // This is safe because we verified the length is exact and cast the pointer
    // to the correct type based on memory layout assumptions.
    let u32_slice = unsafe {
        std::slice::from_raw_parts(u32_slice_ptr, num_u32s)
    };

    Some(u32_slice)
