import org.w3c.dom.Document;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.InputStream;
import java.io.IOException;

public class XmlParser {

    /**
     * Parses an XML configuration document from an InputStream, securely preventing 
     * XML External Entity (XXE) attacks and Billion Laughs attacks by disabling DTD processing.
     *
     * @param in The InputStream containing the untrusted XML configuration.
     * @return The parsed Document object.
     * @throws Exception if parsing fails due to malformed XML or security policy violations.
     */
    public Document parseConfig(InputStream in) throws Exception {
        // 1. Initialize the DocumentBuilderFactory
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // 2. Enforce Security Policy (Mandatory Security Requirements)

        // SR 3: Disable DTD processing entirely by disallowing DOCTYPE declarations.
        // This prevents XXE and DoS attacks related to DTD entities.
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Defense-in-Depth: Further disable potentially dangerous features if supported.
        // Setting secure processing to true is a good general hardening measure.
        factory.setFeature(javax.xml.XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Explicitly disable external entity resolution (Defense in Depth)
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);


        // 3. Create the DocumentBuilder
        DocumentBuilder builder = factory.newDocumentBuilder();

        // 4. Parse the input stream
        return builder.parse(in);
    }

    // Example usage (for demonstration, not part of the core required method)
    /*
    public static void main(String[] args) {
        XmlParser parser = new XmlParser();
        // Assume inputStream is obtained from a network request or file read
